const item = $input.first();
let msg = (item.json.output || '').trim();

// Fallback se IA nao gerou mensagem
if (!msg) {
  const nome = $('setarInfo').first().json.Nome || '';
  const primeiro = nome.split(' ')[0];
  const consultor = $('setarInfo').first().json.NOME_CONSULTOR || 'Consultor';
  msg = `Oi${primeiro ? ', ' + primeiro : ''}! Aqui é ${consultor} da *Federal Malotes* 👋\n\nVi que você demonstrou interesse nos nossos produtos. Somos especialistas em malotes, quadros fiscais, pastas e brindes corporativos — mais de 30 anos no mercado.\n\nPosso te ajudar com um orçamento personalizado? É só responder aqui. 👇`;
}

// Truncar se muito longa (max 900 chars)
if (msg.length > 900) {
  msg = msg.substring(0, 897) + '...';
}

// Anti-alucinacao: substituir precos inventados
msg = msg.replace(/R\$\s*[\d.,]+/g, '[consulte valores]');

return [{ json: { ...item.json, output: msg } }];

// Intervalo em MINUTOS
const MIN_MINUTES = 2;  // 2 min
const MAX_MINUTES = 10; // 10 min

// Último delay em segundos vindo do node "setarInfo"
const prev = Number($items('setarInfo')[0]?.json?.TempoMsg);

function randInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function pickDelay(minM, maxM, prevSec) {
  let tries = 0;
  let seconds;
  do {
    const minutes = randInt(minM, maxM);
    seconds = minutes * 60;
    tries++;
  } while (Number.isFinite(prevSec) && seconds === prevSec && tries < 50);

  if (Number.isFinite(prevSec) && seconds === prevSec) {
    const up = prevSec + 60;
    const down = prevSec - 60;
    const minSec = MIN_MINUTES * 60;
    const maxSec = MAX_MINUTES * 60;
    if (up <= maxSec) seconds = up;
    else if (down >= minSec) seconds = down;
  }
  return seconds;
}

const delaySeconds = pickDelay(MIN_MINUTES, MAX_MINUTES, prev);

return [{ json: { delaySeconds } }];
